function HotspotDrawer({ imageSrc, hotspots, focusHsId, onFocusHs, onDrawn, onClose, onDeleteHs, onEditHs, onPlayHs, onSave, note, onNoteChange }) {
  const containerRef = useRef(null);
  const [dragging, setDragging] = useState(false);
  const [start, setStart] = useState(null);
  const [current, setCurrent] = useState(null);
  const [noteOpen, setNoteOpen] = useState(false);
  const NOTE_MAX = 400;

  const pct = (e) => {
    const rect = containerRef.current.getBoundingClientRect();
    const src = e.touches?.[0] || e.changedTouches?.[0] || e;
    const cx = src.clientX;
    const cy = src.clientY;
    return { x: Math.max(0,Math.min(100,((cx-rect.left)/rect.width)*100)), y: Math.max(0,Math.min(100,((cy-rect.top)/rect.height)*100)) };
  };

  const onDown = (e) => {
    // Ignore if tapping a hotspot button (let those handle their own clicks)
    if(e.target.closest(".hs-btn")) return;
    e.preventDefault();
    const p=pct(e);
    setStart(p); setCurrent(p); setDragging(true);
  };
  const onMove = useCallback((e) => {
    if(!dragging) return;
    if(e.cancelable) e.preventDefault();
    setCurrent(pct(e));
  },[dragging]);
  const onUp = useCallback((e) => {
    if(!dragging) return;
    setDragging(false);
    // For touchend, use changedTouches since touches is empty
    const touch = e.changedTouches ? e.changedTouches[0] : null;
    const synth = touch ? { clientX: touch.clientX, clientY: touch.clientY } : e;
    const end = pct(synth);
    const x=Math.min(start.x,end.x), y=Math.min(start.y,end.y);
    const w=Math.abs(end.x-start.x), h=Math.abs(end.y-start.y);
    if(w>3&&h>3) onDrawn({x,y,w,h});
    setStart(null); setCurrent(null);
  },[dragging,start]);

  useEffect(()=>{
    window.addEventListener("mousemove", onMove);
    window.addEventListener("mouseup", onUp);
    window.addEventListener("touchmove", onMove, { passive: false });
    window.addEventListener("touchend", onUp);
    return()=>{
      window.removeEventListener("mousemove", onMove);
      window.removeEventListener("mouseup", onUp);
      window.removeEventListener("touchmove", onMove);
      window.removeEventListener("touchend", onUp);
    };
  },[onMove,onUp]);

  const draft = dragging&&start&&current ? {
    x:Math.min(start.x,current.x), y:Math.min(start.y,current.y),
    w:Math.abs(current.x-start.x), h:Math.abs(current.y-start.y)
  } : null;

  return (
    <div style={{ position:"fixed", inset:0, zIndex:1000, background:"#111", display:"flex", flexDirection:"column", touchAction:"none" }}>
      <div style={{ position:"relative", flex:1, overflow:"hidden" }}>
        <div style={{ position:"absolute", top:16, left:16, zIndex:20, display:"flex", flexDirection:"column", gap:8 }}>
          <div style={{ display:"flex", alignItems:"center", gap:8 }}>
            <div style={{ background:"rgba(28,28,28,0.92)", borderRadius:8, width:34, height:34, display:"flex", alignItems:"center", justifyContent:"center", color:"#fff", fontWeight:700, fontSize:14, cursor:"pointer", flexShrink:0 }}>?</div>
            <div style={{ background:"rgba(28,28,28,0.92)", borderRadius:8, padding:"6px 14px", color:"#fff", fontSize:13, fontWeight:500 }}>Drag and drop to select area</div>
          </div>
          <button
            onClick={()=>setNoteOpen(o=>!o)}
            style={{ background:noteOpen?"rgba(91,155,213,0.85)":"rgba(28,28,28,0.92)", borderRadius:8, width:34, height:34, border:"none", cursor:"pointer", display:"flex", alignItems:"center", justifyContent:"center", transition:"background 0.15s" }}
            title="Add note"
          >
            <svg width="17" height="17" viewBox="0 0 24 24" fill="none" stroke="#fff" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
              <path d="M12 20h9"/><path d="M16.5 3.5a2.121 2.121 0 0 1 3 3L7 19l-4 1 1-4 12.5-12.5z"/>
            </svg>
          </button>
        </div>
        <button onClick={onClose} style={{ ...S.closeBtn, position:"absolute", top:14, right:14, zIndex:20, background:"rgba(28,28,28,0.92)" }}>
          <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round"><line x1="18" y1="6" x2="6" y2="18"/><line x1="6" y1="6" x2="18" y2="18"/></svg>
        </button>

        {!noteOpen && (hotspots.length > 0 || note.trim().length > 0) && (
          <div style={{ position:"absolute", bottom:20, right:20, zIndex:30 }}>
            <button onClick={onSave} style={{ background:"#34c759", color:"#fff", border:"none", borderRadius:12, padding:"12px 26px", fontSize:15, fontWeight:700, cursor:"pointer", boxShadow:"0 4px 20px rgba(52,199,89,0.4)" }}>Save scene</button>
          </div>
        )}
        <div
          ref={containerRef}
          onMouseDown={onDown}
          onTouchStart={onDown}
          onClick={()=>onFocusHs(null)}
          style={{ position:"relative", cursor:"crosshair", userSelect:"none", lineHeight:0, width:"100%", height:"100%", touchAction:"none" }}
        >
          <img src={imageSrc} alt="" style={{ width:"100%", height:"100%", objectFit:"cover", position:"absolute", inset:0 }} />
          {hotspots.map(hs=>{
            const isFocused = focusHsId === hs.id;
            const barAbove = hs.y > 12;
            return (
              <React.Fragment key={hs.id}>
                <div
                  onClick={e=>{ e.stopPropagation(); onFocusHs(isFocused ? null : hs.id); }}
                  style={{ position:"absolute", left:hs.x+"%", top:hs.y+"%", width:hs.w+"%", height:hs.h+"%", border:isFocused?"2.5px solid rgba(91,155,213,0.9)":"2px solid rgba(255,255,255,0.5)", borderRadius:4, boxSizing:"border-box", background:isFocused?"rgba(91,155,213,0.18)":"transparent", cursor:"pointer", transition:"border 0.12s, background 0.12s" }}
                />
                {isFocused && (
                  <div style={{ position:"absolute", left:hs.x+"%", top: barAbove ? `calc(${hs.y}% - 46px)` : `calc(${hs.y+hs.h}% + 6px)`, zIndex:30, display:"flex", alignItems:"center", gap:6, background:"rgba(18,18,18,0.9)", borderRadius:10, padding:"5px 8px", backdropFilter:"blur(8px)", pointerEvents:"all" }}>
                    <button className="hs-btn hs-btn-danger" onClick={e=>{e.stopPropagation();onDeleteHs(hs.id);}}>
                      <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round"><polyline points="3 6 5 6 21 6"/><path d="M19 6l-1 14H6L5 6"/><path d="M10 11v6M14 11v6"/><path d="M9 6V4h6v2"/></svg>
                    </button>
                    <div onClick={e=>{e.stopPropagation();onEditHs(hs.id);}} style={{ background:"rgba(50,50,50,0.9)", borderRadius:8, padding:"5px 13px", color:"#fff", fontSize:13, fontWeight:500, cursor:"pointer", maxWidth:200, overflow:"hidden", textOverflow:"ellipsis", whiteSpace:"nowrap", minWidth:60 }}>
                      {hs.label||<span style={{color:"#999",fontStyle:"italic"}}>Add label…</span>}
                    </div>
                    <button className="hs-btn" onClick={e=>{e.stopPropagation();onPlayHs(hs.label);}}>
                      <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round"><circle cx="12" cy="12" r="10"/><circle cx="12" cy="12" r="3"/></svg>
                    </button>
                    <button className="hs-btn" onClick={e=>{e.stopPropagation();onFocusHs(null);}}>
                      <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round"><line x1="18" y1="6" x2="6" y2="18"/><line x1="6" y1="6" x2="18" y2="18"/></svg>
                    </button>
                  </div>
                )}
              </React.Fragment>
            );
          })}
          {draft&&(
            <div style={{ position:"absolute", left:draft.x+"%", top:draft.y+"%", width:draft.w+"%", height:draft.h+"%", border:"2px dashed rgba(255,255,255,0.9)", borderRadius:4, boxSizing:"border-box", background:"rgba(255,255,255,0.07)", pointerEvents:"none" }} />
          )}
        </div>
        {/* Note panel */}
        {noteOpen && (
          <div style={{ position:"absolute", bottom:0, left:0, right:0, zIndex:25, padding:"0 0 0 0" }}>
            <div style={{ background:"rgba(255,255,255,0.97)", borderRadius:"16px 16px 0 0", padding:"10px 14px 14px", boxShadow:"0 -4px 24px rgba(0,0,0,0.18)" }}>
              {/* Toolbar */}
              <div style={{ display:"flex", alignItems:"center", gap:8, marginBottom:8 }}>
                <button className="hs-btn hs-btn-danger" onClick={()=>{ onNoteChange(""); }} title="Delete note">
                  <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round"><polyline points="3 6 5 6 21 6"/><path d="M19 6l-1 14H6L5 6"/><path d="M10 11v6M14 11v6"/><path d="M9 6V4h6v2"/></svg>
                </button>
                <button className="hs-btn" onClick={()=>{ if(note) speak(note); }} title="Play note">
                  <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round"><circle cx="12" cy="12" r="10"/><circle cx="12" cy="12" r="3"/></svg>
                </button>
                <div style={{ background:"rgba(40,40,40,0.85)", borderRadius:8, padding:"4px 12px", color:"#fff", fontSize:12, fontWeight:600 }}>
                  {note.length}/{NOTE_MAX} characters
                </div>
                <div style={{ flex:1 }} />
                <button className="hs-btn" onClick={()=>setNoteOpen(false)} title="Close">
                  <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round"><line x1="18" y1="6" x2="6" y2="18"/><line x1="6" y1="6" x2="18" y2="18"/></svg>
                </button>
              </div>
              {/* Text area */}
              <textarea
                value={note}
                onChange={e=>{ if(e.target.value.length<=NOTE_MAX) onNoteChange(e.target.value); }}
                placeholder="Add a note about this scene…"
                style={{ width:"100%", boxSizing:"border-box", border:"1.5px solid #dde3ec", borderRadius:10, padding:"10px 14px", fontSize:14, lineHeight:1.5, resize:"none", outline:"none", color:"#222", fontFamily:"inherit", minHeight:72, maxHeight:100 }}
              />
              {(hotspots.length > 0 || note.trim().length > 0) && (
                <div style={{ display:"flex", justifyContent:"flex-end", marginTop:10 }}>
                  <button onClick={onSave} style={{ background:"#34c759", color:"#fff", border:"none", borderRadius:12, padding:"10px 28px", fontSize:15, fontWeight:700, cursor:"pointer", boxShadow:"0 3px 14px rgba(52,199,89,0.4)" }}>Save scene</button>
                </div>
              )}
            </div>
          </div>
        )}
      </div>
    </div>
  );
}

function LabelModal({ title, initial, onSave, onCancel }) {
  const [text, setText] = useState(initial||"");
  const ref = useRef(null);
  useEffect(()=>{ ref.current?.focus(); },[]);
  return (
    <div style={{ ...S.overlay, zIndex:1050 }}>
      <div style={{ background:"#fff", borderRadius:16, padding:"24px 24px 20px", width:"min(340px,90vw)", boxShadow:"0 8px 40px rgba(0,0,0,0.22)" }}>
        <div style={{ fontSize:17, fontWeight:700, marginBottom:14, color:"#111" }}>{title}</div>
        <input ref={ref} value={text} onChange={e=>setText(e.target.value)}
          onKeyDown={e=>{ if(e.key==="Enter"&&text.trim()) onSave(text.trim()); }}
          style={{ width:"100%", boxSizing:"border-box", border:"1.5px solid #dde3ec", borderRadius:10, padding:"10px 14px", fontSize:15, outline:"none", color:"#222" }} />
        <div style={{ display:"flex", justifyContent:"flex-end", gap:10, marginTop:18 }}>
          <button onClick={onCancel} style={{ background:"none", border:"none", fontSize:15, color:"#666", cursor:"pointer", padding:"8px 12px" }}>Cancel</button>
          <button onClick={()=>text.trim()&&onSave(text.trim())}
            style={{ background:text.trim()?"#34c759":"#b5dfc2", color:"#fff", border:"none", borderRadius:10, padding:"9px 22px", fontSize:15, fontWeight:600, cursor:text.trim()?"pointer":"default", transition:"background 0.15s" }}>Save</button>
        </div>
      </div>
    </div>
  );
}

function HotspotActionBar({ hs, onDelete, onEdit, onPlay, onClose, style }) {
  return (
    <div style={{ position:"absolute", zIndex:20, display:"flex", alignItems:"center", gap:6, background:"rgba(18,18,18,0.88)", borderRadius:10, padding:"5px 8px", backdropFilter:"blur(8px)", ...style }}>
      <button className="hs-btn hs-btn-danger" onClick={onDelete} title="Delete">
        <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round"><polyline points="3 6 5 6 21 6"/><path d="M19 6l-1 14H6L5 6"/><path d="M10 11v6M14 11v6"/><path d="M9 6V4h6v2"/></svg>
      </button>
      <div onClick={onEdit} style={{ background:"rgba(55,55,55,0.9)", borderRadius:8, padding:"5px 13px", color:"#fff", fontSize:13, fontWeight:500, cursor:"pointer", maxWidth:180, overflow:"hidden", textOverflow:"ellipsis", whiteSpace:"nowrap", minWidth:50 }}>
        {hs.label||<span style={{ color:"#999", fontStyle:"italic" }}>Add label…</span>}
      </div>
      <button className="hs-btn" onClick={onPlay} title="Play">
        <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round"><circle cx="12" cy="12" r="10"/><circle cx="12" cy="12" r="3"/></svg>
      </button>
      <button className="hs-btn" onClick={onClose} title="Close">
        <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round"><line x1="18" y1="6" x2="6" y2="18"/><line x1="6" y1="6" x2="18" y2="18"/></svg>
      </button>
    </div>
  );
}


// ── Add Category Modal ────────────────────────────────────────────────────────
function AddCategoryModal({ onSave, onClose, newCatName, setNewCatName, newCatEmoji, setNewCatEmoji }) {
  const nameRef = React.useRef(null);
  const emojiRef = React.useRef(null);

  // Focus emoji input first so native keyboard opens ready for emoji
  React.useEffect(() => { emojiRef.current?.focus(); }, []);

  const handleEmojiChange = (e) => {
    // Extract only the first grapheme cluster (one emoji)
    const val = e.target.value;
    if (!val) { setNewCatEmoji(""); return; }
    // Use Intl.Segmenter if available, otherwise just take the first two chars (most emojis are 2 code units)
    if (typeof Intl !== "undefined" && Intl.Segmenter) {
      const segs = [...new Intl.Segmenter().segment(val)];
      setNewCatEmoji(segs[0]?.segment || val.slice(0, 2));
    } else {
      const arr = [...val];
      setNewCatEmoji(arr[0] || "");
    }
    // Move focus to name input after picking emoji
    setTimeout(() => nameRef.current?.focus(), 50);
  };

  return (
    <div style={S.overlay}>
      <div style={{ background:"#fff", borderRadius:16, padding:"24px 24px 20px", width:"min(380px,92vw)", boxShadow:"0 8px 40px rgba(0,0,0,0.2)", display:"flex", flexDirection:"column", gap:16 }}>
        <div style={{ fontSize:18, fontWeight:700, color:"#111" }}>Add category</div>

        {/* Emoji tap area — opens native keyboard */}
        <div>
          <div style={{ fontSize:14, fontWeight:600, color:"#555", marginBottom:8 }}>Choose an emoji</div>
          <div style={{ display:"flex", alignItems:"center", gap:12 }}>
            <div style={{ position:"relative", flexShrink:0 }}>
              {/* Visible emoji display */}
              <div style={{ width:64, height:64, borderRadius:14, border:"2px solid #dde3ec", background:"#f9f9f9", display:"flex", alignItems:"center", justifyContent:"center", fontSize:36, cursor:"pointer" }}
                onClick={()=>emojiRef.current?.focus()}>
                {newCatEmoji || <span style={{fontSize:24,color:"#ccc"}}>+</span>}
              </div>
              {/* Hidden input that receives emoji keyboard input */}
              <input
                ref={emojiRef}
                value={newCatEmoji}
                onChange={handleEmojiChange}
                inputMode="text"
                style={{ position:"absolute", inset:0, opacity:0, cursor:"pointer", fontSize:36, border:"none", outline:"none", background:"transparent", width:"100%", height:"100%" }}
              />
            </div>
            <span style={{ fontSize:14, color:"#888", lineHeight:1.4 }}>
              Tap the box and use your{" "}emoji{" "}keyboard to pick an emoji
            </span>
          </div>
        </div>

        {/* Category name input */}
        <div>
          <div style={{ fontSize:14, fontWeight:600, color:"#555", marginBottom:8 }}>Category name</div>
          <input
            ref={nameRef}
            value={newCatName}
            onChange={e=>setNewCatName(e.target.value)}
            onKeyDown={e=>{ if(e.key==="Enter" && newCatName.trim()) onSave(); }}
            placeholder="e.g. Hobbies"
            style={{ width:"100%", boxSizing:"border-box", border:"1.5px solid #dde3ec", borderRadius:10, padding:"10px 14px", fontSize:16, outline:"none", color:"#222", fontFamily:"inherit" }}
          />
        </div>

        {/* Live preview */}
        <div style={{ display:"flex", alignItems:"center", gap:10, background:"#f5f7ff", borderRadius:10, padding:"10px 14px" }}>
          <span style={{ fontSize:28 }}>{newCatEmoji || "?"}</span>
          <span style={{ fontSize:16, fontWeight:600, color: newCatName ? "#333" : "#aaa", fontStyle: newCatName ? "normal" : "italic" }}>
            {newCatName || "Category name"}
          </span>
        </div>

        {/* Action buttons */}
        <div style={{ display:"flex", justifyContent:"flex-end", gap:10 }}>
          <button onClick={onClose} style={{ background:"none", border:"none", fontSize:16, color:"#666", cursor:"pointer", padding:"8px 12px", fontFamily:"inherit" }}>Cancel</button>
          <button
            onClick={()=>newCatName.trim()&&onSave()}
            style={{ background:newCatName.trim()?"#34c759":"#b5dfc2", color:"#fff", border:"none", borderRadius:10, padding:"10px 22px", fontSize:16, fontWeight:700, cursor:newCatName.trim()?"pointer":"default", transition:"background 0.15s", fontFamily:"inherit" }}
          >Save</button>
        </div>
      </div>
    </div>
  );
}

export default function App() {
  const [categories, setCategories] = useState(DEFAULT_CATEGORIES);
  const [catIcons, setCatIcons] = useState(DEFAULT_CAT_ICONS);
  const [activeCatId, setActiveCatId] = useState("home");
  const [addCatOpen, setAddCatOpen] = useState(false);
  const [newCatName, setNewCatName] = useState("");
  const [newCatEmoji, setNewCatEmoji] = useState("🏠");
  const [scenes, setScenes] = useState(INITIAL_SCENES);
  const [activeSceneId, setActiveSceneId] = useState(1);
  const [selectedHsId, setSelectedHsId] = useState(null);
  const [wfStep, setWfStep] = useState(null);
  const [wfImage, setWfImage] = useState(null);
  const [wfHotspots, setWfHotspots] = useState([]);
  const [wfPendingRect, setWfPendingRect] = useState(null);
  const [wfFocusHsId, setWfFocusHsId] = useState(null);
  const [wfEditHsId, setWfEditHsId] = useState(null);
  const [editTarget, setEditTarget] = useState(null);
  const [wfNote, setWfNote] = useState("");
  const [wfNoteOpen, setWfNoteOpen] = useState(false);
  const [noteMode, setNoteMode] = useState(false); // home screen note display
  const [isSpeakingNote, setIsSpeakingNote] = useState(false);

  const categoryScenes = scenes.filter(s=>s.category===activeCatId);
  const activeScene = scenes.find(s=>s.id===activeSceneId) || categoryScenes[0] || scenes[0];
  const activeHs = selectedHsId ? activeScene?.hotspots.find(h=>h.id===selectedHsId) : null;
  const wfFocusHs = wfFocusHsId ? wfHotspots.find(h=>h.id===wfFocusHsId) : null;

  const cancelWf = ()=>{ setWfStep(null); setWfImage(null); setWfHotspots([]); setWfPendingRect(null); setWfFocusHsId(null); };

  const handleSaveCat = () => {
    if (!newCatName.trim()) return;
    const name = newCatName.trim();
    // Capitalise first letter
    const display = name.charAt(0).toUpperCase() + name.slice(1);
    const cid = display.toLowerCase();
    if (categories.find(c => c.toLowerCase() === cid)) return; // already exists
    setCategories(prev => [...prev, display]);
    setCatIcons(prev => ({ ...prev, [display]: newCatEmoji }));
    setActiveCatId(cid);
    setSelectedHsId(null);
    setNoteMode(false);
    setAddCatOpen(false);
  };

  const handleSaveScene = ()=>{
    if(!wfHotspots.length && !wfNote.trim()) return;
    const ns={ id:Date.now(), label:"New scene", category:activeCatId, src:wfImage, thumb:wfImage, hotspots:wfHotspots, note:wfNote };
    setScenes(p=>[...p,ns]);
    setActiveSceneId(ns.id);
    setSelectedHsId(null);
    setWfNote("");
    cancelWf();
  };

  return (
    <div style={{ fontFamily:"'DM Sans', sans-serif", background:"#ececec", height:"100dvh", maxHeight:"100dvh", display:"flex", flexDirection:"column", userSelect:"none", overflow:"hidden", position:"fixed", inset:0 }}>
      <style>{`
        .cat-tab{cursor:pointer;padding:8px 12px;border-radius:10px;font-size:16px;font-weight:500;background:#fff;border:2px solid #ddd;transition:all 0.15s;color:#333;line-height:1.3;display:flex;flex-direction:column;align-items:center;gap:4px;flex-shrink:0;box-sizing:border-box;}
        .cat-tab:hover{background:#e8f0fe;border-color:#aac4f5;}
        .cat-tab.active{background:#fff;border:2.5px solid #5b9bd5;color:#1a4a8a;font-weight:700;}
        .cat-icon{font-size:22px;line-height:1;}
        .cat-label{font-size:16px;font-weight:500;white-space:nowrap;}
        .thumb-item{cursor:pointer;border-radius:8px;overflow:hidden;border:3px solid transparent;transition:border 0.15s,transform 0.1s;flex-shrink:0;background:#ccc;}
        .thumb-item:hover{transform:scale(1.02);border-color:#aac4f5;}
        .thumb-item.active{border-color:#5b9bd5;}
        .thumb-item img{width:100%;height:clamp(70px,8vw,100px);object-fit:cover;display:block;}
        .hotspot-zone{position:absolute;border-radius:4px;cursor:pointer;border:2px solid rgba(255,255,255,0.5);transition:background 0.15s,border-color 0.15s;box-sizing:border-box;}
        .hotspot-zone:hover{background:rgba(255,255,255,0.1);border-color:rgba(255,255,255,0.8);}
        .hotspot-zone.selected{background:rgba(91,155,213,0.2);border-color:rgba(91,155,213,0.9);border-width:2.5px;}
        .pencil-btn{position:absolute;top:12px;left:12px;width:44px;height:44px;border-radius:10px;background:rgba(50,50,50,0.72);border:none;cursor:pointer;display:flex;align-items:center;justify-content:center;transition:background 0.15s;z-index:10;backdrop-filter:blur(4px);}
        .pencil-btn:hover{background:rgba(20,20,20,0.9);}
        .play-btn{display:flex;align-items:center;gap:7px;background:#fff;border:2px solid #ccc;border-radius:10px;padding:9px 18px;font-size:16px;font-weight:600;cursor:pointer;transition:background 0.15s;flex-shrink:0;color:#222;}
        .play-btn:hover{background:#e8f4ff;border-color:#5b9bd5;}
        .play-btn:disabled{opacity:0.42;cursor:default;}
        .add-cat-btn{width:48px;height:48px;border-radius:10px;background:#e8e8e8;border:2px solid #ccc;font-size:24px;cursor:pointer;display:flex;align-items:center;justify-content:center;flex-shrink:0;color:#888;transition:background 0.15s;}
        .add-cat-btn:hover{background:#d0e4ff;border-color:#5b9bd5;color:#5b9bd5;}
        .add-scene{display:flex;flex-direction:column;align-items:center;justify-content:center;height:clamp(70px,8vw,100px);border:2px dashed #bbb;border-radius:8px;cursor:pointer;background:#f0f0f0;flex-shrink:0;color:#999;gap:3px;transition:all 0.15s;}
        .add-scene:hover{background:#e0ecff;border-color:#5b9bd5;color:#5b9bd5;}
        .hs-btn{background:rgba(60,60,60,0.85);border:none;border-radius:7px;width:30px;height:30px;display:flex;align-items:center;justify-content:center;cursor:pointer;color:#fff;transition:background 0.15s;flex-shrink:0;}
        .hs-btn:hover{background:rgba(10,10,10,0.95);}
        .hs-btn-danger:hover{background:rgba(210,45,45,0.9)!important;}
      `}</style>

      {/* Top bar */}
      <div style={{ background:"#fff", borderBottom:"1px solid #ddd", padding:"10px 12px", display:"flex", alignItems:"center", gap:8, overflowX:"auto", flexShrink:0 }}>
        <div style={{ width:50, height:50, borderRadius:10, background:"#c5cfe8", display:"flex", alignItems:"center", justifyContent:"center", flexShrink:0, border:"2px solid #aabce8" }}>
          <svg width="26" height="26" viewBox="0 0 24 24" fill="none" stroke="#4a6fa5" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
            <path d="M20 21v-2a4 4 0 0 0-4-4H8a4 4 0 0 0-4 4v2"/><circle cx="12" cy="7" r="4"/>
          </svg>
        </div>
        {categories.map(cat=>(
          <button key={cat} className={`cat-tab${activeCatId===cat.toLowerCase()?" active":""}`} onClick={()=>{ const cid=cat.toLowerCase(); setActiveCatId(cid); const first=scenes.find(s=>s.category===cid); if(first) setActiveSceneId(first.id); setSelectedHsId(null); setNoteMode(false); }}>
            <span className="cat-icon">{catIcons[cat]}</span>
            <span className="cat-label">{cat} ({scenes.filter(s=>s.category===cat.toLowerCase()).length})</span>
          </button>
        ))}
        <button className="add-cat-btn" onClick={()=>{ setNewCatName(""); setNewCatEmoji("🏠"); setAddCatOpen(true); }}>+</button>
      </div>

      {/* Main */}
      <div style={{ flex:1, display:"flex", overflow:"hidden", minHeight:0, height:0 }}>
        {/* Viewer */}
        <div style={{ flex:1, minWidth:0, display:"flex", flexDirection:"column", background:"#111" }}>
          <div style={{ flex:1, position:"relative", overflow:"hidden", display:"flex", alignItems:"center", justifyContent:"center" }}>
            {categoryScenes.length === 0 ? (
              <div style={{ display:"flex", flexDirection:"column", alignItems:"center", justifyContent:"center", gap:16, color:"#888", padding:32 }}>
                <span style={{ fontSize:48 }}>{catIcons[categories.find(c=>c.toLowerCase()===activeCatId)] || "📷"}</span>
                <span style={{ fontSize:18, fontWeight:600, color:"#666" }}>No scenes yet</span>
                <span style={{ fontSize:16, color:"#aaa", textAlign:"center" }}>Tap + Add scene to add your first image</span>
              </div>
            ) : (
            <div style={{ position:"relative", width:"100%", aspectRatio:"4/3", maxHeight:"100%", overflow:"hidden", flexShrink:0 }}>
            <img src={activeScene.src} alt={activeScene.label} style={{ width:"100%", height:"100%", objectFit:"cover", display:"block" }} />
            {activeScene.hotspots.map(hs=>(
              <div key={hs.id} className={`hotspot-zone${selectedHsId===hs.id?" selected":""}`}
                style={{ left:hs.x+"%", top:hs.y+"%", width:hs.w+"%", height:hs.h+"%" }}
                onClick={()=>setSelectedHsId(id=>id===hs.id?null:hs.id)} />
            ))}

            <button className={`pencil-btn${noteMode?"  active-pencil":""}`} onClick={()=>{ setNoteMode(m=>!m); setSelectedHsId(null); setIsSpeakingNote(false); window.speechSynthesis.cancel(); }}
              style={{ background: noteMode?"rgba(91,155,213,0.85)":"rgba(50,50,50,0.72)" }}>
              <svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="#fff" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                <path d="M12 20h9"/><path d="M16.5 3.5a2.121 2.121 0 0 1 3 3L7 19l-4 1 1-4 12.5-12.5z"/>
              </svg>
            </button>
            </div>
            )}
          </div>
          {/* Bottom bar */}
          <div style={{ background:"rgba(255,255,255,0.94)", backdropFilter:"blur(6px)", borderTop:"1px solid #ddd", padding:"10px 14px", display:"flex", alignItems:"center", gap:12, flexShrink:0 }}>
            <div style={{ flex:1, minHeight:42, background:"#fff", border:"1.5px solid #dde3ec", borderRadius:10, display:"flex", alignItems:"center", padding:"8px 14px", fontSize:16, color:(noteMode&&activeScene.note)||activeHs?.label?"#222":"#aaa", fontStyle:(noteMode&&activeScene.note)||activeHs?.label?"normal":"italic", letterSpacing:0.2, lineHeight:1.5, overflowY:"auto", maxHeight:80 }}>
              {noteMode ? (activeScene.note||<span style={{color:"#aaa",fontStyle:"italic"}}>No note for this scene</span>) : (activeHs?.label||"Tap an area on the screen")}
            </div>
            <button className="play-btn"
              disabled={noteMode ? !activeScene.note : !activeHs?.label}
              onClick={()=>{
                if(noteMode){
                  if(isSpeakingNote){ window.speechSynthesis.cancel(); setIsSpeakingNote(false); }
                  else { speak(activeScene.note); setIsSpeakingNote(true); setTimeout(()=>setIsSpeakingNote(false), (activeScene.note?.length||0)*65+500); }
                } else { speak(activeHs?.label); }
              }}>
              {noteMode&&isSpeakingNote ? "Pause" : "Play"}
              {noteMode&&isSpeakingNote ? (
                <svg width="17" height="17" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.2" strokeLinecap="round" strokeLinejoin="round"><rect x="6" y="4" width="4" height="16"/><rect x="14" y="4" width="4" height="16"/></svg>
              ) : (
                <svg width="17" height="17" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.2" strokeLinecap="round" strokeLinejoin="round">
                  <polygon points="11 5 6 9 2 9 2 15 6 15 11 19 11 5"/>
                  <path d="M19.07 4.93a10 10 0 0 1 0 14.14"/>
                  <path d="M15.54 8.46a5 5 0 0 1 0 7.07"/>
                </svg>
              )}
            </button>
          </div>
        </div>

        {/* Thumbnail strip */}
        <div style={{ width:"max(100px, 15vw)", background:"#e2e2e2", borderLeft:"1px solid #ccc", display:"flex", flexDirection:"column", gap:5, padding:"6px", overflowY:"auto", flexShrink:0 }}>
          {scenes.filter(s=>s.category===activeCatId).map(scene=>(
            <div key={scene.id} className={`thumb-item${scene.id===activeSceneId?" active":""}`}
              onClick={()=>{ setActiveSceneId(scene.id); setSelectedHsId(null); setNoteMode(false); setIsSpeakingNote(false); window.speechSynthesis.cancel(); }}>
              <img src={scene.thumb||scene.src} alt={scene.label} />
            </div>
          ))}
          <div className="add-scene" onClick={()=>setWfStep("pick")}>
            <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.2" strokeLinecap="round">
              <line x1="12" y1="5" x2="12" y2="19"/><line x1="5" y1="12" x2="19" y2="12"/>
            </svg>
            <span style={{ fontSize:16, fontWeight:500 }}>Add scene</span>
          </div>
        </div>
      </div>

      {/* Workflow overlays */}
      {addCatOpen && (
        <AddCategoryModal
          onSave={handleSaveCat}
          onClose={()=>setAddCatOpen(false)}
          newCatName={newCatName}
          setNewCatName={setNewCatName}
          newCatEmoji={newCatEmoji}
          setNewCatEmoji={setNewCatEmoji}
        />
      )}
      {wfStep==="pick"&&(
        <AddImageModal onSelect={src=>{ setWfImage(src); setWfHotspots([]); setWfFocusHsId(null); setWfStep("draw"); }} onClose={cancelWf} />
      )}
      {(wfStep==="draw"||wfStep==="label")&&wfImage&&(
        <HotspotDrawer
          imageSrc={wfImage}
          hotspots={wfHotspots}
          focusHsId={wfFocusHsId}
          onFocusHs={setWfFocusHsId}
          onDrawn={rect=>{ setWfPendingRect(rect); setWfStep("label"); }}
          onClose={cancelWf}
          onDeleteHs={hsId=>{ const upd=wfHotspots.filter(h=>h.id!==hsId); setWfHotspots(upd); setWfFocusHsId(upd.length?upd[upd.length-1].id:null); }}
          onEditHs={hsId=>setWfEditHsId(hsId)}
          onPlayHs={label=>speak(label)}
          onSave={handleSaveScene}
          note={wfNote}
          onNoteChange={setWfNote}
        />
      )}
      {wfStep==="label"&&(
        <LabelModal title="Add label" onSave={label=>{ const nh={id:uid(),...wfPendingRect,label}; const upd=[...wfHotspots,nh]; setWfHotspots(upd); setWfFocusHsId(nh.id); setWfPendingRect(null); setWfStep("draw"); }} onCancel={()=>{ setWfPendingRect(null); setWfStep("draw"); }} />
      )}

      {/* Action bar during draw step */}



      {wfEditHsId&&(
        <LabelModal title="Edit label" initial={wfHotspots.find(h=>h.id===wfEditHsId)?.label} onSave={label=>{ setWfHotspots(p=>p.map(h=>h.id!==wfEditHsId?h:{...h,label})); setWfEditHsId(null); }} onCancel={()=>setWfEditHsId(null)} />
      )}
      {editTarget&&(
        <LabelModal title="Edit label" initial={scenes.find(s=>s.id===editTarget.sceneId)?.hotspots.find(h=>h.id===editTarget.hsId)?.label}
          onSave={label=>{ setScenes(p=>p.map(s=>s.id!==editTarget.sceneId?s:{...s,hotspots:s.hotspots.map(h=>h.id!==editTarget.hsId?h:{...h,label})})); setEditTarget(null); }}
          onCancel={()=>setEditTarget(null)} />
      )}
    </div>
  );
}

const S = {
  overlay:{ position:"fixed", inset:0, zIndex:1000, background:"rgba(0,0,0,0.65)", display:"flex", alignItems:"center", justifyContent:"center", backdropFilter:"blur(3px)" },
  modal:{ position:"relative", boxShadow:"0 20px 60px rgba(0,0,0,0.45)" },
  closeBtn:{ position:"absolute", top:14, right:14, width:34, height:34, borderRadius:8, border:"none", cursor:"pointer", display:"flex", alignItems:"center", justifyContent:"center", color:"#fff" },
};
